package src.samples.org.apache.cocoon.samples.flow.prefs;

public class User { String login ; String password ; String firstName ; String lastName ; String email ; public User ( String login , String password , String firstName , String lastName , String email ) { this . login = login ; this . password = password ; this . firstName = firstName ; this . lastName = lastName ; this . email = email ; } public int hashCode ( ) { return login . hashCode ( ) ; } public boolean equals ( Object obj ) { User anotherUser = ( User ) obj ; return anotherUser . login . equals ( login ) ; } public void setLogin ( String argLogin ) { this . login = argLogin ; } public String getLogin ( ) { return this . login ; } public String getPassword ( ) { return this . password ; } public void setPassword ( String argPassword ) { this . password = argPassword ; } public String getFirstName ( ) { return this . firstName ; } public void setFirstName ( String argFirstName ) { this . firstName = argFirstName ; } public String getLastName ( ) { return this . lastName ; } public void setLastName ( String argLastName ) { this . lastName = argLastName ; } public String getEmail ( ) { return this . email ; } public void setEmail ( String argEmail ) { this . email = argEmail ; } }